sql:
SELECT AVG(water_quality_index) AS avg_water_quality
FROM water_bodies
WHERE type = 'Lake';

SELECT AVG(w.water_quality_index) AS average_water_quality_index
FROM water_bodies w
INNER JOIN hydrological_metrics h ON w.water_body_id = h.water_body_id;

SELECT max_depth
FROM water_bodies
WHERE water_quality_index = (SELECT MIN(water_quality_index) FROM water_bodies);

SELECT AVG(temperature) AS average_temperature
FROM weather_data
WHERE water_body_id = (SELECT water_body_id FROM water_bodies WHERE name = 'Lake Tahoe');

SELECT ecosystem_type, AVG(average_depth) AS average_depth
FROM water_bodies
GROUP BY ecosystem_type;

external_knowledge:
- 'significant drop' refers to an average drawdown percentage greater than 10%;
- 'water body name' refers to the 'name' column in the 'water_bodies' table;
- 'percentage decrease in water level' refers to the 'drawdown' in the 'hydrological_metrics' table.

- "typical water quality" refers to the average water quality;
- "freshwaters" refers to water bodies with a freshwater ecosystem type;
- "reported period of 2020" refers to the end date range from '2020-01-01' to '2020-12-31'.

sql:
SELECT name, type, location
FROM water_bodies
ORDER BY name ASC;

SELECT water_body_id, water_quality_at_start
FROM hydrological_metrics
WHERE start_date BETWEEN '2020-01-01' AND '2020-12-31';

external_knowledge:
- "top researchers" refers to researchers with the highest number of access logs;
- "involvement" in this context measures by the number of times a researcher accesses the records, indicating frequent engagement or visits;
- "typical recovery times" refers to the average recovery times for water bodies monitored by each researcher, implying the water bodies' recovery times after significant changes or disturbances.

sql:
SELECT AVG(drawdown) AS average_drawdown
FROM hydrological_metrics
WHERE start_date BETWEEN '2021-01-01' AND '2021-12-31';
